#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

inline size_t chunk_base(const uint fusion_idx) {
#ifndef BLOCK_STRIDED
  return (((size_t)fusion_idx * (size_t)get_global_size(0)) +
          (size_t)get_global_id(0)) *
         (size_t)ELEMENTS_PER_THREAD;
#else
  return ((((size_t)get_group_id(0) * (size_t)FUSION_DEGREE) +
           (size_t)fusion_idx) *
              (size_t)get_local_size(0) +
          (size_t)get_local_id(0)) *
         (size_t)ELEMENTS_PER_THREAD;
#endif
}

__kernel void benchmark_func(const class_T seed, __global class_T* data) {
  (void)seed;

  class_T sum = (class_T)(0);
  const size_t out_idx = chunk_base(0);

  for (uint fusion = 0; fusion < (uint)FUSION_DEGREE; ++fusion) {
    const size_t base_idx = chunk_base(fusion);

    const class_T f0 = data[base_idx + 0];
    const class_T f1 = data[base_idx + ((ELEMENTS_PER_THREAD > 1) ? 1 : 0)];
    const class_T f2 = data[base_idx + ((ELEMENTS_PER_THREAD > 2) ? 2 : 0)];
    const class_T f3 = data[base_idx + ((ELEMENTS_PER_THREAD > 3) ? 3 : 0)];
    const class_T f4 = data[base_idx + ((ELEMENTS_PER_THREAD > 4) ? 4 : 0)];
    const class_T f5 = data[base_idx + ((ELEMENTS_PER_THREAD > 5) ? 5 : 0)];
    const class_T f6 = data[base_idx + ((ELEMENTS_PER_THREAD > 6) ? 6 : 0)];
    const class_T f7 = data[base_idx + ((ELEMENTS_PER_THREAD > 7) ? 7 : 0)];

    for (uint i = 0; i < (uint)ELEMENTS_PER_THREAD; ++i) {
      const class_T v = data[base_idx + (size_t)i];

      class_T t0 = v;
      class_T t1 = v;
      class_T t2 = v;
      class_T t3 = v;
      class_T t4 = v;
      class_T t5 = v;
      class_T t6 = v;
      class_T t7 = v;

      for (uint j = 0; j < (uint)(COMPUTE_ITERATIONS / 8); ++j) {
        t0 = t0 * t0 + f0;
        t1 = t1 * t1 + f1;
        t2 = t2 * t2 + f2;
        t3 = t3 * t3 + f3;
        t4 = t4 * t4 + f4;
        t5 = t5 * t5 + f5;
        t6 = t6 * t6 + f6;
        t7 = t7 * t7 + f7;
      }

#if (COMPUTE_ITERATIONS % 8) > 0
      t0 = t0 * t0 + f0;
#endif
#if (COMPUTE_ITERATIONS % 8) > 1
      t1 = t1 * t1 + f1;
#endif
#if (COMPUTE_ITERATIONS % 8) > 2
      t2 = t2 * t2 + f2;
#endif
#if (COMPUTE_ITERATIONS % 8) > 3
      t3 = t3 * t3 + f3;
#endif
#if (COMPUTE_ITERATIONS % 8) > 4
      t4 = t4 * t4 + f4;
#endif
#if (COMPUTE_ITERATIONS % 8) > 5
      t5 = t5 * t5 + f5;
#endif
#if (COMPUTE_ITERATIONS % 8) > 6
      t6 = t6 * t6 + f6;
#endif

      sum += t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
    }
  }

  data[out_idx] = sum;
}
